                componentStats[i].addValue(subSamples[i][j]);
            }
        }


        for (int i = 0; i < totalSample.length; i++) {
            totalStats.addValue(totalSample[i]);
        }


        assertEquals(totalStats.getSummary(), aggregate.getSummary());

    }

